local function C_46()
local script = G2L["46"];
	script.Parent.MouseButton1Click:Connect(function()
	
	--[[
	
	mesh disco f3x
	
	made by fro0kidd
	
	not remove credits pls
	
	--]]
	
	local me = game.Players.LocalPlayer
	local char = me.Character
	
	local tool
	for _, v in ipairs(me:GetDescendants()) do
		if v.Name == "SyncAPI" then
			tool = v.Parent
			break
		end
	end
	if not tool then
		for _, v in ipairs(game.ReplicatedStorage:GetDescendants()) do
			if v.Name == "SyncAPI" then
				tool = v.Parent
				break
			end
		end
	end
	if not tool then
		warn("yo ur not have f3x")
		return
	end
	
	remote = tool.SyncAPI.ServerEndpoint
	
	function _(args)
		spawn(function()
			local success, result
			if remote:IsA("RemoteFunction") then
				success, result = pcall(function()
					return remote:InvokeServer(unpack(args))
				end)
			else
				remote:FireServer(unpack(args))
				success = true
			end
		end)
	end
	
	function CreateMeshes(part)
		local args = {
			[1] = "CreateMeshes",
			[2] = {
				[1] = {
					["Part"] = part
				}
			}
		}
		_(args)
	end
	
	function SyncMesh(part, meshType)
		local args = {
			[1] = "SyncMesh",
			[2] = {
				[1] = {
					["Part"] = part,
					["MeshType"] = meshType
				}
			}
		}
		_(args)
	end
	
	function Color(part, color)
		local args = {
			[1] = "SyncColor",
			[2] = {
				[1] = {
					["Part"] = part,
					["Color"] = color,
					["UnionColoring"] = false
				}
			}
		}
		_(args)
	end
	
	local meshes = {
		Enum.MeshType.Brick,
		Enum.MeshType.Cylinder,
		Enum.MeshType.Head,
		Enum.MeshType.Sphere,
		Enum.MeshType.Wedge,
		Enum.MeshType.Torso
	}
	
	while true do
		wait(0.1)
	
		if not char or not char.Parent then
			char = me.Character
			if not char then 
				wait(1)
				continue 
			end
		end
	
		local bodyParts = {
			char:FindFirstChild("Head"),
			char:FindFirstChild("Torso") or char:FindFirstChild("UpperTorso"),
			char:FindFirstChild("Left Arm") or char:FindFirstChild("LeftUpperArm") or char:FindFirstChild("LeftLowerArm"),
			char:FindFirstChild("Right Arm") or char:FindFirstChild("RightUpperArm") or char:FindFirstChild("RightLowerArm"),
			char:FindFirstChild("Left Leg") or char:FindFirstChild("LeftUpperLeg") or char:FindFirstChild("LeftLowerLeg"),
			char:FindFirstChild("Right Leg") or char:FindFirstChild("RightUpperLeg") or char:FindFirstChild("RightLowerLeg")
		}
	
		for _, part in ipairs(bodyParts) do
