local function C_4e()
local script = G2L["4e"];
	script.Parent.MouseButton1Click:Connect(function()
	
	--[[
	
	face all f3x
	
	made by fro0kidd
	
	not remove credits pls
	
	--]]
	
	
		local player = game.Players.LocalPlayer
	
		local char = player.Character or player.CharacterAdded:Wait()
	
	
		local tool
	
		for _, v in ipairs(player:GetDescendants()) do
	
			if v.Name == "SyncAPI" then
	
				tool = v.Parent
	
				break
	
			end
	
		end
	
	
		if not tool then return warn("no tool 😨") end
	
	
		local remote = tool.SyncAPI.ServerEndpoint
	
	
		local function call(args)
	
			remote:InvokeServer(unpack(args))
	
		end
	
	
		function createpart(cf, parent)
	
			call({
	
				[1] = "CreatePart",
	
				[2] = "Normal",
	
				[3] = cf,
	
				[4] = parent
	
			})
	
		end
	
	
		function size(part, size, cf)
	
			if not part then return end
	
			call({
	
				[1] = "SyncResize",
	
				[2] = {
	
					[1] = {
	
						Part = part,
	
						Size = size,
	
						CFrame = cf
	
					}
	
				}
	
			})
	
		end
	
	
		function trans(part, int)
	
			if not part then return end
	
			call({
	
				[1] = "SyncMaterial",
	
				[2] = {
	
					[1] = {
	
						Part = part,
	
						Transparency = int
	
					}
	
				}
	
			})
	
		end
	
	
		function collision(part, bool)
	
			if not part then return end
	
			call({
	
				[1] = "SyncCollision",
	
				[2] = {
	
					[1] = {
	
						Part = part,
	
						CanCollide = bool
	
					}
	
				}
	
			})
	
		end
	
	
		function anchor(bool, part)
	
			if not part then return end
	
			call({
	
				[1] = "SyncAnchor",
	
				[2] = {
	
					[1] = {
	
						Part = part,
	
						Anchored = bool
	
					}
	
				}
	
			})
	
		end
	
	
		function textures(part, face)
	
			if not part then return end
	
			call({
	
				[1] = "CreateTextures",
	
				[2] = {
	
					[1] = {
	
						Part = part,
	
						Face = face,
	
						TextureType = "Decal"
	
					}
	
				}
	
			})
	
		end
	
	
		function decal(part, id, face)
	
			if not part then return end
	
			call({
	
				[1] = "SyncTexture",
	
				[2] = {
	
					[1] = {
	
						Part = part,
	
						Face = face,
	
						TextureType = "Decal",
	
						Texture = "rbxassetid://" .. id
	
					}
	
				}
	
			})
	
		end
	
	
		function weld(p1, p2, lead)
	
			if not p1 or not p2 then return end
	
			call({
	
				[1] = "CreateWelds",
	
				[2] = {p1, p2},
	
				[3] = lead
	
			})
	
		end
	
	
		local fc = {}
	
	
		function f(p)
	
			if not p.Character then return end
	
	
			local char2 = p.Character
	
			local head = char2:FindFirstChild("Head")
	
			local hrp = char:FindFirstChild("HumanoidRootPart")
	
	
			if not head or not hrp then return end
	
	
			if fc[p] then
	
				call({
	
					[1] = "Remove",
	
					[2] = {fc[p]}
	
				})
	
				fc[p] = nil
	
			end
	
	
			local cf = head.CFrame * CFrame.new(0, 1, 0)
	
	
			trans(head, 1)
	
			createpart(cf, workspace)
	
	
			task.wait(0.2)
	
	
			for _, v in ipairs(workspace:GetChildren()) do
	
				if v:IsA("BasePart") and (v.Position - cf.Position).Magnitude < 1 then
	
	
					anchor(true, hrp)
	
	
					size(v, Vector3.new(3,3,0.001), cf)
	
					collision(v, false)
	
					trans(v, 1)
	
	
					textures(v, Enum.NormalId.Front)
	
					decal(v, "126822200248647", Enum.NormalId.Front)
	
	
					textures(v, Enum.NormalId.Back)
	
					decal(v, "126822200248647", Enum.NormalId.Back)
	
	
					weld(v, hrp, v)
	
	
					anchor(false, v)
	
					anchor(false, hrp)
	
	
					fc[p] = v
	
					break
	
				end
	
			end
	
		end
	
	
		for _, p in ipairs(game.Players:GetPlayers()) do
	
			f(p)
	
		end
	
	
		-- for _, p in ipairs(game.Players:GetPlayers()) do nil(p) end
	end)
end;
