local function C_66()
local script = G2L["66"];
	local innerFrame = script.Parent 
	local textLabel = innerFrame:FindFirstChild("TextLabel")	
	local TweenService = game:GetService("TweenService")	
	
	
	local originalRotation = innerFrame.Rotation	
	
	
	local shouldSway = true	
	
	
	local function sway()	
		while shouldSway do	
			local swayRight = TweenService:Create(	
				innerFrame, 	
				TweenInfo.new(1, Enum.EasingStyle.Sine, Enum.EasingDirection.InOut),	
				{Rotation = originalRotation + 5}	
			)	
			swayRight:Play()	
			swayRight.Completed:Wait()	
	
			if not shouldSway then break end	
	
	
			local swayLeft = TweenService:Create(	
				innerFrame, 	
				TweenInfo.new(1, Enum.EasingStyle.Sine, Enum.EasingDirection.InOut),	
				{Rotation = originalRotation - 5}	
			)	
			swayLeft:Play()	
			swayLeft.Completed:Wait()	
		end	
	end	
	task.spawn(sway)
end;
